('b2381915-193b-4abc-8acc-18b0df1121ba','Vs 28',NULL,59.852,16.5337,NULL,NULL,NULL,NULL,NULL,'Passar ihop med Vs 27.',NULL,NULL,'Västmanland','Sweden'),
('4a38b36e-5b2b-4fb1-821d-b6e9cb8896fb','Vs 11','L 995',59.6102,16.542,'[: kufri : auk : hoburi… … …sla : …þ… : man :]','"Guðfríðr(?)/"Kofri(?) ok "Holmbjǫr[n](?) … "[Gí]sla(?) [gó]ð[an](?) mann.',NULL,'Guðfríðr(?)/Kofri(?) and Holmbjǫrn(?) … Gísli(?) a good(?) man.',NULL,NULL,'Fragment av runsten','Sten','Västmanland','Sweden'),
