('8901297e-5d64-4d0a-ad0f-24e82625f4f7','Vs 21',NULL,59.7015,16.5799,'… …(n) × þina × at × sta(i)(n)biu-n × … nrfa × kahsn … …ris…','… [stei]n þenna at "Steinbjǫ[r]n … arfa(?) "Gansa(?)/"Knasa(?) … …',NULL,'… this stone in memory of Steinbjǫrn … the heir of(?) Gansi(?)/Knasi(?) …',NULL,NULL,'Fragment av runsten','Granit','Västmanland','Sweden'),
('e06ffe61-bb04-4a88-b35f-bd86cfeb86c7','Vs 18','L 1002',59.72,16.4181,'(k)hunaltr · liet resa · sthin · þinsa · iftir · kerfast · sun sen · trek| |kuþan · auk · uas farin · til eklans · hiolbi · kuþ · salu · hans','"Gunnvaldr lét reisa stein þenna eptir "Geirfast, son sinn, dreng góðan, ok var farinn til "Englands. Hjalpi "Guð sálu hans.','Gunnald lät resa denna sten efter Gerfast, sin son, en god ung man, och han hade farit till England. Hjälpe Gud hans själ.','Gunnvaldr had this stone raised in memory of Geirfastr, his son, a good valiant man. And (he) had travelled to England. May God help his soul.',NULL,NULL,'Runsten','Granit','Västmanland','Sweden'),
('985d8db9-a6c9-4d39-abd8-c51a683572c3','Vs 7','L 2002',59.6125,16.5412,'[fuþork fuþoro-k hk-b]','<fuþork> … …',NULL,'<fuþork> …',NULL,'Futharkinskrift.','Tegelsten','Tegel','Västmanland','Sweden'),
('f4d7ba40-9566-4422-9484-328130c558bd','Vs 1',NULL,59.5125,16.3424,'+ kuþlefʀ + seti : stff : auk : sena : þasi : uftiʀ slakua : sun : sia : etaþr : austr · i · karusm ·','"Guðlæifʀ satti staf ok stæina þasi æftiʀ "Slagva, sun sinn, ændaðr austr i "Garðum(?)/"Chorezm(?).','Gudlev satte stav och dessa stenar efter Slagve, sin son. Han ändades österut i Gårdarike(?)/Chorezm(?).','Guðleifr placed the staff and these stones in memory of Slagvi, his son, (who) met his end in the east in Garðar(?)/Chorezm(?).',NULL,'Parsten till Vs 2.','Runsten','Grå och rödaktig granit','Västmanland','Sweden'),
('d7ac2108-f304-4874-b0bf-f3e26e7d1142','Vs 4',NULL,59.5643,16.3535,'… …-þan × isun × isʀn × bʀkia nu × kuþ il×… …','… [gó]ðan(?), son(?) sinn(?). Biðja(?) nú(?) "Guð(?) hjal[pa](?) …',NULL,'… good(?), his(?) son(?). Now(?) (they) pray(?) to God(?) to help(?) …','Ung, eventuellt 1100-talet',NULL,'Fragment av runsten','Rödgrå granit','Västmanland','Sweden'),
('4f085233-9a3c-4bf4-b73d-3e3e9b48cc17','Vs 30','L 1015',60.0887,16.5391,'…-rfastr + raist… …','"[Þo]rfastr(?) ræist[i] …',NULL,'Þorfastr(?) raised …',NULL,'Ytterligare ett fragment ligger intill runstenen, säkerligen del av samma runsten, se Raä 4:2 i Möklinta sn och Källström 2014a.','Runsten','Röd sandsten','Västmanland','Sweden'),
('b75ad3ab-3c16-4450-b8aa-dc8ea785c8f3','Vs 29','L 1014|B 1083',59.932,16.6176,'+ uisti + yk + alfton + litu + akua + stin + yftir + ulmo + faþur + sen + yk + ulfast + bruþur + sen + lifsten + risi + runi + þisa +','"Viseti ok "Halfdan letu haggva stæin æftiʀ "Holma, faður sinn, ok "Holmfast, broður sinn. "Lifstæinn risti runi þessa.',NULL,'Véseti and Halfdan had the stone cut in memory of Holmi, their father, and Holmfastr, their brother. Hlífsteinn carved these runes.',NULL,'Under B 1083 beskrivs även Vs 29.','Runsten','Granit med mörkare inslag','Västmanland','Sweden'),
('1c8e48c9-0ebd-44b1-88a1-2770a82ba813','Vs 8',NULL,59.6125,16.5412,'…þ a^u^e m','… Ave "M[aria].',NULL,'… Ave Maria.',NULL,'latininskrift','Putsinskrift','Kalkputs','Västmanland','Sweden')
) as v(id, signum, alt, lat, lng, translit, norm, tsv, ten, dating, notes, otype, material, landscape, country)
where not exists (
  select 1 from public.runic_inscriptions ri
  where lower(regexp_replace(ri.signum,'\s+',' ','g')) = lower(regexp_replace(v.signum,'\s+',' ','g'))
)
on conflict (id) do nothing;
